        job_id,
        req.user.id,
        title || `Screening: ${job.rows[0].title}`,
        description || `AI screening interview for ${job.rows[0].title} candidates`,
        JSON.stringify(finalQuestions),
        time_limit_minutes || 45,
        auto_send_on_apply || false
