      )
      VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
      ON CONFLICT (interview_id, question_index)
      DO UPDATE SET
        analysis_data = $3,
        eye_contact_score = $4,
        expression_score = $5,
        body_language_score = $6,
        voice_score = $7,
        presentation_score = $8`,
      [
        interview_id,
